plugin.detectCode:
const t = input.trim();
if (!t) return 0;
const hasSentences = (t.match(/[.!?][\s"'\)]+[A-Z]/g) || []).length;
return hasSentences > 1 ? 0.8 : 0.3;

plugin.executeCode:
// Split on sentence-ending punctuation followed by whitespace and a capital letter.
const t = input.trim();
const sentences = [];
let buf = '';
for (let i = 0; i < t.length; i++) {
  buf += t[i];
  if (/[.!?]/.test(t[i])) {
    // Check if next non-space char is uppercase or end of string
    let j = i + 1;
    while (j < t.length && t[j] === ' ') j++;
    if (j >= t.length || /[A-Z"'\(]/.test(t[j])) {
      sentences.push(buf.trim());
      buf = '';
      i = j - 1; // skip spaces, loop will i++
    }
  }
}
if (buf.trim()) sentences.push(buf.trim());
return { output: sentences.join('\n'), outputLanguage: 'text' };
